bd list --status=in_progress --json --limit=0 2>/dev/null | python3 -c "
import sys, json
data = json.load(sys.stdin)
for d in data:
    assignee = d.get('assignee','') or ''
    if 'claude_temp/polecats' in assignee:
        print(f\"{d['id']}: {d['title']} assigned={assignee} [{d['status']}]\")
if not any('claude_temp/polecats' in (d.get('assignee','') or '') for d in data):
    print('No in_progress beads assigned to claude_temp polecats')
" 2>/dev/null

